static int mutex_lock(unsigned long *m)
{
    int c;
    int flags = FUTEX_WAIT;
    if (!processes)
        flags |= FUTEX_PRIVATE_FLAG;

    c = cmpxchg(m, 0, 1);
    if (!c)
        return 0;

    if (c == 1)
        c = xchg(m, 2);

    while (c) {
        sys_futex(m, flags, 2, NULL, NULL, 0);
        c = xchg(m, 2);
    }

    return 0;
}
