	__le16 uid;
	/** @size: lower 32 bits of file size */
	__le32 size;
	/** @atime: last access time */
	__le32 atime;
	/** @ctime: last change time */
	__le32 ctime;
	/** @mtime: last modification time */
	__le32 mtime;
