	__le32 blockcnt;
	/** @flags: inode flags */
	__le32 flags;
	/** @osd1: operating system specific data */
	__le32 osd1;
	/** @b: block map or extent tree */
	union {
		struct datablocks {
			__le32 dir_blocks[INDIRECT_BLOCKS];
			__le32 indir_block;
			__le32 double_indir_block;
			__le32 triple_indir_block;
		} blocks;
		char symlink[60];
