static int mutex_unlock(unsigned long *m)
{
    int flags = FUTEX_WAKE;
    if (!processes)
        flags |= FUTEX_PRIVATE_FLAG;

    if (*m == 2)
        *m = 0;
    else if (xchg(m, 0) == 1)
        return 0;

    sys_futex(m, flags, 1, NULL, NULL, 0);

    return 0;
}
