case -ECONNABORTED:	/* hardware forced ep reset */
case -ECONNRESET:	/* request dequeued */
case -ESHUTDOWN:	/* disconnect from host */
VDBG(mutex, "%s gone (%d), %d/%d\n", ep->name, semaphore,
