u32 file_size = reg->file_size;
// Declare a variable to hold the block list size
unsigned int blocks;
// Calculate the number of blocks required to represent the file.
blocks = (file_size + blk_size - 1) / blk_size;
// Check if the file is fragmented
if (SQFS_IS_FRAGMENTED(fragment))
