static struct dpll_pin *dpll_pin_alloc(u64 clock_id, u32 pin_idx, struct module *module,
const struct dpll_pin_properties *prop)
{
int err;
struct dpll_pin *new_pin;
// Allocate memory for a new dpll_pin structure and zero-initialize it
new_pin = kzalloc(sizeof(*new_pin), GFP_KERNEL);
// Check if memory allocation failed and return an error pointer if so
if (!new_pin)
return ERR_PTR(-ENOMEM);
// Set the pin index for the new dpll_pin structure
new_pin->pin_idx = pin_idx;
// Set the clock ID for the new dpll_pin structure
new_pin->clock_id = clock_id;
// Associate the provided module with the new dpll_pin structure
new_pin->module = module;
// Check if the pin type in properties is within valid range and warn if not
if (prop->type < DPLL_PIN_TYPE_MUX || prop->type > DPLL_PIN_TYPE_MAX) {
// Set the return value to indicate an invalid argument error
err = -EINVAL;
// Jump to the error handling section for pin properties
goto err_pin_prop;
}
// Duplicate the pin properties from the source to the destination
err = dpll_pin_prop_dup(prop, &new_pin->prop);
// Check if property duplication failed and jump to error handling if so
if (err)
goto err_pin_prop;
// Initialize the reference count for the new dpll_pin structure
refcount_set(&new_pin->refcount, 1);
// Initialize the dpll_refs xarray with allocation flags
xa_init_flags(&new_pin->dpll_refs, XA_FLAGS_ALLOC);
// Initialize the parent_refs xarray with allocation flags
xa_init_flags(&new_pin->parent_refs, XA_FLAGS_ALLOC);
// Allocate a unique ID for the new dpll_pin structure in a cyclic manner
err = xa_alloc_cyclic(&new_pin->dpll_refs, &new_pin->id, new_pin, xa_limit_32b, NULL, GFP_KERNEL);
// Check if ID allocation failed and jump to error handling if so
if (err)
goto err_xa_alloc;
// Return the newly allocated and initialized dpll_pin structure
return new_pin;
err_xa_alloc:
// Destroy the dpll_refs xarray to free resources
xa_destroy(&new_pin->dpll_refs);
// Destroy the parent_refs xarray to free resources
xa_destroy(&new_pin->parent_refs);
// Free the duplicated pin properties to release memory
dpll_pin_prop_free(&new_pin->prop);
err_pin_prop:
// Free the allocated memory for the dpll_pin structure
kfree(new_pin);
// Return an error pointer with the appropriate error code
return ERR_PTR(err);
