// Format the name of the outbound resource based on the index
snprintf(ob_res_name, sizeof(ob_res_name), "%s-ob%d", pdev->name, i);
// Retrieve the resource by name from the platform device
ob_res = platform_get_resource(pdev, IORESOURCE_MEM, i);
// Check if the resource was not found
if (!ob_res) {
// Log an error message indicating the missing outbound window
dev_err(pci->dev, "Outbound window %s not available\n", ob_res_name);
// Return an error code for invalid argument
return -EINVAL;
}
// Attempt to request the memory region for the resource
if (!devm_request_mem_region(pci->dev, ob_res->start, resource_size(ob_res), ob_res_name)) {
// Log an error message indicating the failure to request the memory region
dev_err(pci->dev, "Failed to request outbound mem region for %s\n", ob_res_name);
// Return an error code for I/O error
return -EIO;
}
// Set the physical base address of the outbound window
ep->ob_mapped_addr[i] = ob_res->start;
// Set the size of the outbound window
ep->ob_window[i].page_size = resource_size(ob_res);
ep->ob_window[i].phys_offset = 0;
ep->ob_window[i].cpu_addr = (void *)ob_res->start;
ep->ob_window[i].len = resource_size(ob_res);
// Increment the outbound window count
ep->num_ob_windows++;
}
// Update the number of outbound windows in the endpoint structure
return 0;
}

