struct xsk_buff_pool *xp_create_and_assign_umem(struct xdp_sock *xs,
struct xdp_umem *umem)
{
// Determine if the umem uses unaligned chunks based on its flags
bool useUnalignedChunks = !!(umem->flags & XDP_UMEM_UNALIGNED_CHUNK_FLAG);
// Declare a pointer for the xsk_buff_pool structure
struct xsk_buff_pool *pool;
// Declare a pointer for the xdp_buff_xsk structure
struct xdp_buff_xsk *xskb;
// Declare variables for loop iteration and number of entries
int i;
u64 numEntries = umem->chunks;
// Allocate memory for the xsk_buff_pool structure with zero initialization
pool = kvzalloc(struct_size(pool, free_heads, numEntries), GFP_KERNEL);
// Check if memory allocation for the pool was successful
if (!pool)
goto out;
// Allocate memory for the heads array within the pool
pool->heads = kvzalloc(numEntries * sizeof(*pool->heads), GFP_KERNEL);
// Check if memory allocation for the heads array was successful
if (!pool->heads)
goto out_free_pool;
// Check if the xdp_sock has a tx queue
if (xs->tx)
// Attempt to allocate tx descriptors for the pool
if (xp_alloc_tx_descs(pool, xs))
goto out_free_heads;
// Set the chunk mask for the pool based on the umem's chunk size
pool->chunk_mask = (u64)(numEntries)-1;
// Set the address count for the pool based on the umem's size
pool->addrs_cnt = umem->size >> PAGE_SHIFT;
// Set the heads count for the pool based on the umem's chunks
pool->heads_cnt = numEntries;
// Set the free heads count for the pool based on the umem's chunks
pool->free_heads_cnt = numEntries;
// Set the headroom for the pool based on the umem's headroom
pool->headroom = umem->headroom;
// Set the chunk size for the pool based on the umem's chunk size
pool->chunk_size = umem->chunk_size;
// Calculate and set the chunk shift for the pool
pool->chunk_shift = ilog2(pool->chunk_size);
// Set the unaligned flag for the pool based on the umem's unaligned status
pool->unaligned = useUnalignedChunks;
// Calculate and set the frame length for the pool
pool->frame_len = round_down(PAGE_SIZE, pool->chunk_size);
// Assign the umem to the pool
pool->umem = umem;
// Assign the addresses from the umem to the pool
pool->addrs = umem->addrs;
// Set the tx metadata length for the pool based on the umem
pool->tx_metadata_len = umem->tx_metadata_len;
// Set the tx software checksum flag for the pool based on the umem's flags
pool->tx_sw_csum = !!(umem->flags & XDP_UMEM_TX_SW_CSUM);
// Initialize the free list head for the pool
INIT_LIST_HEAD(&pool->free_list);
// Initialize the xskb list head for the pool
INIT_LIST_HEAD(&pool->xskb_list);
// Initialize the xsk tx list head for the pool
INIT_LIST_HEAD(&pool->xsk_tx_list);
// Initialize the spin lock for the xsk tx list
spin_lock_init(&pool->xsk_tx_list_lock);
// Initialize the spin lock for the completion queue
spin_lock_init(&pool->cq_lock);
// Set the reference count for the pool's users
refcount_set(&pool->users, 1);
// Assign the temporary free queue from the xdp_sock to the pool
pool->fq = xs->fq_tmp ? : xs->fq;
// Assign the temporary completion queue from the xdp_sock to the pool
pool->cq = xs->cq_tmp ? : xs->cq;
// Iterate over each free head in the pool
for (i = 0; i < pool->free_heads_cnt; i++) {
// Get the current xdp_buff_xsk from the pool's heads array
xskb = &pool->heads[i];
// Assign the pool to the current xdp_buff_xsk
xskb->pool = pool;
// Set the frame size for the current xdp_buff_xsk
xskb->xdp.frame_sz = pool->chunk_size;
// Initialize the free list node for the current xdp_buff_xsk
INIT_LIST_HEAD(&xskb->list_node);
// Initialize the xskb list node for the current xdp_buff_xsk
INIT_LIST_HEAD(&xskb->skb_list_node);
// Check if the pool is unaligned
if (pool->unaligned)
// Assign the current xdp_buff_xsk to the free heads array
list_add(&xskb->list_node, &pool->free_list);
else
// Initialize the xskb address for the current xdp_buff_xsk
xp_init_xskb_addr(xskb, pool, i * pool->chunk_size);
}
// Return the initialized pool
return pool;
out_free_heads:
kvfree(pool->heads);
out_free_pool:
kvfree(pool);
out:
// Return NULL to indicate failure
return NULL;
}

