#include <linux/irqreturn.h>
#include <linux/printk.h>
#include <linux/workqueue.h>
/* Assumed definitions for interrupt bits */
#define V3D_INT_OOM (1 << 0)
#define V3D_INT_BIN_DONE (1 << 1)
#define V3D_INT_RENDER_DONE (1 << 2)
#define V3D_INT_CSD_DONE (1 << 3)
#define V3D_INT_GMP_VIOLATION (1 << 4)
/* Assumed offsets for core interrupt registers */
#define V3D_CORE_INT_STS 0x00 /* core interrupt status register offset */
#define V3D_CORE_INT_CLR 0x04 /* core interrupt clear register offset */
static irqreturn_t v3d_irq(int irq, void *arg)
{
struct v3d_dev *v3d = arg;
u32 intsts;
irqreturn_t status = IRQ_NONE;
// Read the interrupt status from the V3D core
intsts = V3D_CORE_READ(0, V3D_CORE_INT_STS);
// Acknowledge the interrupts by writing the status back to the clear register
V3D_CORE_WRITE(0, V3D_CORE_INT_CLR, intsts);
// Check if the interrupt status indicates an out-of-memory condition
if (intsts & V3D_INT_OOM) {
// Schedule work to handle the overflow memory condition
schedule_work(&v3d->overflow_mem_work);
// Mark the interrupt as handled
status = IRQ_HANDLED;
}
// Check if the interrupt status indicates that the binning process is done
if (intsts & V3D_INT_BIN_DONE) {
struct v3d_fence *fence;
// Retrieve the fence associated with the binning job
fence = to_v3d_fence(v3d->bin_job->base.irq_fence);
// Trace the binning completion interrupt
trace_v3d_bcl_irq(&v3d->drm, fence->seqno);
// Signal the completion of the binning job
dma_fence_signal(&fence->base);
// Mark the interrupt as handled
status = IRQ_HANDLED;
}
// Check if the interrupt status indicates that the rendering process is done
if (intsts & V3D_INT_RENDER_DONE) {
struct v3d_fence *fence;
// Retrieve the fence associated with the rendering job
fence = to_v3d_fence(v3d->render_job->base.irq_fence);
// Trace the rendering completion interrupt
trace_v3d_rcl_irq(&v3d->drm, fence->seqno);
// Signal the completion of the rendering job
dma_fence_signal(&fence->base);
// Mark the interrupt as handled
status = IRQ_HANDLED;
}
// Check if the interrupt status indicates that the compute shader dispatch is done
if (intsts & V3D_INT_CSD_DONE) {
struct v3d_fence *fence;
// Retrieve the fence associated with the compute shader dispatch job
fence = to_v3d_fence(v3d->csd_job->base.irq_fence);
// Trace the compute shader dispatch completion interrupt
trace_v3d_csd_irq(&v3d->drm, fence->seqno);
// Signal the completion of the compute shader dispatch job
dma_fence_signal(&fence->base);
// Mark the interrupt as handled
status = IRQ_HANDLED;
}
// Check for GMP violation interrupt and log an error if it occurs
if (intsts & V3D_INT_GMP_VIOLATION)
dev_err(v3d->drm.dev, "GMP Violation\n");
// If using a single IRQ line and no core IRQs were handled, check the hub for MMU IRQs
if (v3d->single_irq_line && status == IRQ_NONE)
status |= v3d_hub_irq(irq, v3d);
// Return the status indicating whether any interrupts were handled
return status;
}

