u64 now = local_clock();
unsigned long flags;
/* See comment in v3d_job_start_stats() */
if (IS_ENABLED(CONFIG_LOCKDEP))
local_irq_save(flags);
else
preempt_disable();
v3d_stats_update(local_stats, now);
v3d_stats_update(global_stats, now);
if (IS_ENABLED(CONFIG_LOCKDEP))
local_irq_restore(flags);
else
preempt_enable();
}
