static void bnxt_re_start_irq(void *handle, struct bnxt_msix_entry *ent) {
// Retrieve the device information from the auxiliary device handle
struct bnxt_re_en_dev_info *en_info = (struct bnxt_re_en_dev_info *)handle;
// Declare pointers to various structures used in the function
struct bnxt_re_dev *rdev = en_info->rdev;
struct bnxt_qplib_rcfw *rcfw;
struct bnxt_qplib_nq *nq;
struct bnxt_msix_entry *msix_ent = &(rdev->nqr)->msix_entries;
int indx, rc;
// Initialize the rdev pointer to point to the rdev structure in en_info
rdev = en_info->rdev;
// Initialize the msix_ent pointer to point to the msix_entries in nqr
msix_ent = &(rdev->nqr)->msix_entries;
// Initialize the rcfw pointer to point to the rcfw structure in rdev
rcfw = &rdev->rcfw;
// Check if the ent parameter is NULL
if (!ent) {
// Log an error message indicating failure to restart IRQs
pr_err("Failed to restart IRQs");
// Return early since ent is NULL
return;
}
// Update the vector values in the device structure with new vectors
for (indx = 0; indx < rdev->nqr->num_msix; indx++)
// Update the vector for each msix entry
msix_ent[indx] = ent[indx];
// Start the RCFW IRQ with the appropriate vector
rc = bnxt_qplib_rcfw_start_irq(rcfw, msix_ent[BNXT_RE_AEQ_IDX].vector, false);
if (rc) {
// Log a warning message if reinitialization of CREQ fails
pr_warning("Failed to reinitialize CREQ on restarting IRQs");
// Return early since RCFW IRQ start failed
return;
}
// Loop through the NQ indices starting from BNXT_RE_NQ_IDX
for (indx = BNXT_RE_NQ_IDX ; indx < rdev->nqr->num_msix; indx++) {
// Initialize the nq pointer to point to the appropriate NQ structure
nq = &((rdev->nqr)->npqs)[indx - BNXT_RE_NQ_IDX];
// Start the NQ IRQ with the appropriate vector
rc = bnxt_qplib_nq_start_irq(nq, indx - 1, msix_ent[indx].vector, false);
if (rc) {
// Log a warning message if reinitialization of NQ fails
pr_warning("Failed to reinitialize NQ%d on restarting IRQs", indx - 1);
// Return early since NQ IRQ start failed
return;
}
}
} // End of Implementation
